// Build notification HTML inline when backend didn't pre-render
const d = $input.item.json;
const eventType = d.eventType || 'event';
const ts = d.timestamp ? new Date(d.timestamp).toLocaleString('en-GB') : new Date().toLocaleString('en-GB');
const biz = d.businessName || 'RealFlow';

let body = '';
if (eventType === 'new_lead') {
  body = `
    <h2 style="color:#6366f1">New Lead Received</h2>
    <p><strong>Customer:</strong> ${d.customerName || 'Unknown'}</p>
    <p><strong>Email:</strong> ${d.customerEmail || '—'}</p>
    <p><strong>Phone:</strong> ${d.customerPhone || '—'}</p>
    <p><strong>From:</strong> ${d.fromAddress || '—'}</p>
    <p><strong>To:</strong> ${d.toAddress || '—'}</p>
    <p><strong>Moving Date:</strong> ${d.movingDate || '—'}</p>
    <p><strong>Services:</strong> ${Array.isArray(d.services) ? d.services.join(', ') : d.services || '—'}</p>
    <p><strong>Confidence:</strong> ${d.confidence || '—'}%</p>
    <p><small>Received: ${ts}</small></p>
  `;
} else if (eventType === 'workflow_triggered') {
  body = `
    <h2 style="color:#8b5cf6">Workflow Triggered</h2>
    <p>A workflow was triggered for lead <strong>${d.customerName || d.leadId || 'Unknown'}</strong>.</p>
    <p><small>At: ${ts}</small></p>
  `;
} else if (eventType === 'daily_summary') {
  const rows = Object.entries(d.statusBreakdown || {}).map(([s, c]) =>
    `<tr><td style="padding:4px 8px;border:1px solid #ddd;">${s}</td><td style="padding:4px 8px;border:1px solid #ddd;">${c}</td></tr>`
  ).join('');
  body = `
    <h2 style="color:#06b6d4">Daily Lead Summary</h2>
    <p><strong>Leads Today:</strong> ${d.todayCount ?? 0}</p>
    <p><strong>This Week:</strong> ${d.weekCount ?? 0}</p>
    <p><strong>Auto Replies Sent:</strong> ${d.autoReplySent ?? 0}</p>
    <p><strong>Workflows Triggered:</strong> ${d.n8nTriggered ?? 0}</p>
    ${rows ? `<table style="border-collapse:collapse;margin-top:8px;"><tr><th style="padding:4px 8px;border:1px solid #ddd;">Status</th><th style="padding:4px 8px;border:1px solid #ddd;">Count</th></tr>${rows}</table>` : ''}
    <p><small>${ts}</small></p>
  `;
} else {
  body = `<h2>Notification: ${eventType}</h2><pre>${JSON.stringify(d, null, 2)}</pre>`;
}

const html = `<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px;">${body}<hr style="margin-top:24px;"/><p style="color:#aaa;font-size:12px;">Sent by ${biz} via RealFlow</p></body></html>`;

return [{
  json: {
    userId: d.userId || '',
    html,
    subject: d.subject || (eventType === 'new_lead' ? `New Lead: ${d.customerName || 'Unknown'}` : eventType === 'daily_summary' ? `Daily Summary — ${d.todayCount ?? 0} leads today` : `RealFlow Alert: ${eventType}`),
    to: d.to || d.notifyEmail || '',
    eventType,
    leadId: d.leadId || ''
  }
}];
